const raw = $json.text || '';

function extractJson(text) {
  const trimmed = String(text || '').trim();
  if (!trimmed) return null;

  try {
    return JSON.parse(trimmed);
  } catch {}

  const codeBlockMatch = trimmed.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (codeBlockMatch) {
    try {
      return JSON.parse(codeBlockMatch[1].trim());
    } catch {}
  }

  const start = trimmed.indexOf('{');
  const end = trimmed.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    try {
      return JSON.parse(trimmed.slice(start, end + 1));
    } catch {}
  }

  return null;
}

const parsed = extractJson(raw) || {};
const defaultBrief = {
  master_visual_direction: 'Clean premium lifestyle product video, soft daylight, realistic textures, calm modern environment, balanced exposure, smooth camera movement.',
  hero_prompt: 'cinematic product commercial, close-up lifestyle shot of a minimalist skincare serum bottle on a clean beige marble bathroom counter, soft natural daylight, realistic reflections, premium packaging, photorealistic, smooth handheld motion, shallow depth of field, balanced contrast, high detail',
  negative_prompt: 'blurry, low quality, deformed objects, warped hands, extra fingers, duplicate items, floating objects, messy background, text artifacts, logo distortion, oversaturated, harsh contrast, clipped highlights, crushed shadows, flicker, jitter, unrealistic geometry',
  duration_seconds: 4,
  aspect_ratio: '832x480',
  shot_plan: [],
  brand_integration_notes: 'Keep the product readable and central in a believable lifestyle environment.',
  caption_angle: 'A small routine detail that makes the whole morning feel premium.'
};

const brief = { ...defaultBrief, ...parsed };
brief.master_visual_direction = String(brief.master_visual_direction || defaultBrief.master_visual_direction);
brief.hero_prompt = String(brief.hero_prompt || defaultBrief.hero_prompt);
brief.negative_prompt = String(brief.negative_prompt || defaultBrief.negative_prompt);
brief.aspect_ratio = String(brief.aspect_ratio || defaultBrief.aspect_ratio);
brief.brand_integration_notes = String(brief.brand_integration_notes || defaultBrief.brand_integration_notes);
brief.caption_angle = String(brief.caption_angle || defaultBrief.caption_angle);
brief.duration_seconds = Number.isFinite(Number(brief.duration_seconds)) ? Math.max(2, Math.min(6, Number(brief.duration_seconds))) : defaultBrief.duration_seconds;
brief.shot_plan = Array.isArray(brief.shot_plan) ? brief.shot_plan : [];

return [{ json: { ...brief, raw_llm_text: raw, parse_ok: !!extractJson(raw) } }];

const historyRoot = $json || {};
const promptId = $('ComfyUI Render').item.json.prompt_id;
const history = historyRoot[promptId] || historyRoot;
const outputs = history.outputs || {};
let file = null;
for (const nodeId of Object.keys(outputs)) {
  const nodeOutput = outputs[nodeId] || {};
  for (const key of Object.keys(nodeOutput)) {
    const value = nodeOutput[key];
    if (Array.isArray(value)) {
      for (const entry of value) {
        if (entry && entry.filename) {
          file = { ...entry, nodeId, outputKey: key };
          break;
        }
      }
    }
    if (file) break;
  }
  if (file) break;
}
const status = history.status?.status_str || history.status || 'unknown';
if (!file) {
  return [{ json: {
    prompt_id: promptId,
    status,
    ready: false,
    message: 'No downloadable output found yet. Increase the wait time or poll again.'
  } }];
}
const filename = encodeURIComponent(file.filename);
const subfolder = encodeURIComponent(file.subfolder || '');
const type = encodeURIComponent(file.type || 'output');
const downloadUrl = `http://1.34.114.64:62205/view?filename=${filename}&subfolder=${subfolder}&type=${type}&token=092475c6eb5141de21d222d375448c29cdd73c24db753dc2250c5664c3fcbb67`;
return [{ json: {
  prompt_id: promptId,
  status,
  ready: true,
  filename: file.filename,
  subfolder: file.subfolder || '',
  type: file.type || 'output',
  download_url: downloadUrl,
  brief: $('Normalize Render Brief').item.json
} }];
